-- Migration to import Pokemon and Moves data

CREATE TABLE IF NOT EXISTS public.moves (
    id INTEGER PRIMARY KEY,
    name TEXT UNIQUE NOT NULL,
    type TEXT,
    power INTEGER,
    accuracy INTEGER,
    pp INTEGER,
    damage_class TEXT,
    target TEXT,
    priority INTEGER,
    flavor_text TEXT,
    short_effect TEXT
);

CREATE TABLE IF NOT EXISTS public.pokemon (
    id INTEGER PRIMARY KEY,
    name TEXT NOT NULL,
    types TEXT[] NOT NULL,
    hp INTEGER,
    attack INTEGER,
    defense INTEGER,
    special_attack INTEGER,
    special_defense INTEGER,
    speed INTEGER,
    height INTEGER,
    weight INTEGER,
    base_experience INTEGER,
    generation TEXT,
    is_legendary BOOLEAN DEFAULT false,
    is_mythical BOOLEAN DEFAULT false,
    moves TEXT[],
    is_starter BOOLEAN DEFAULT false,
    evolves_from_id INTEGER,
    can_evolve BOOLEAN DEFAULT false
);

ON CONFLICT (id) DO UPDATE SET
name = EXCLUDED.name, type = EXCLUDED.type, power = EXCLUDED.power, accuracy = EXCLUDED.accuracy, pp = EXCLUDED.pp, damage_class = EXCLUDED.damage_class, target = EXCLUDED.target, priority = EXCLUDED.priority, flavor_text = EXCLUDED.flavor_text, short_effect = EXCLUDED.short_effect;

