CREATE INDEX IF NOT EXISTS idx_pokemon_name ON public.pokemon(name);
CREATE INDEX IF NOT EXISTS idx_pokemon_types ON public.pokemon USING GIN(types);
CREATE INDEX IF NOT EXISTS idx_moves_name ON public.moves(name);
CREATE INDEX IF NOT EXISTS idx_pokemon_generation ON public.pokemon(generation);

ALTER TABLE public.pokemon ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.moves ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Anyone can view pokemon" ON public.pokemon;
CREATE POLICY "Anyone can view pokemon" ON public.pokemon FOR SELECT USING (true);

DROP POLICY IF EXISTS "Anyone can view moves" ON public.moves;
CREATE POLICY "Anyone can view moves" ON public.moves FOR SELECT USING (true);
