INSERT INTO public.moves (id, name, type, power, accuracy, pp, damage_class, target, priority, flavor_text, short_effect) VALUES
(1, 'pound', 'normal', 40, 100, 35, 'physical', 'selected-pokemon', 0, 'The target is physically pounded with a long tail, a foreleg, or the like.', 'Inflicts regular damage with no additional effect.'),
(2, 'karate-chop', 'fighting', 50, 100, 25, 'physical', 'selected-pokemon', 0, 'This move can’t be used. It’s recommended that this move is forgotten. Once forgotten, this move can’t be remembered.', 'Has an increased chance for a critical hit.'),
(3, 'double-slap', 'normal', 15, 85, 10, 'physical', 'selected-pokemon', 0, 'This move can’t be used. It’s recommended that this move is forgotten. Once forgotten, this move can’t be remembered.', 'Hits 2-5 times in one turn.'),
(4, 'comet-punch', 'normal', 18, 85, 15, 'physical', 'selected-pokemon', 0, 'This move can’t be used. It’s recommended that this move is forgotten. Once forgotten, this move can’t be remembered.', 'Hits 2-5 times in one turn.'),
(5, 'mega-punch', 'normal', 80, 85, 20, 'physical', 'selected-pokemon', 0, 'The target is slugged by a punch thrown with muscle-packed power.', 'Inflicts regular damage with no additional effect.'),
(6, 'pay-day', 'normal', 40, 100, 20, 'physical', 'selected-pokemon', 0, 'Coins are hurled at the target to inflict damage. Money is earned after the battle.', 'Scatters money on the ground worth five times the user''s level.'),
(7, 'fire-punch', 'fire', 75, 100, 15, 'physical', 'selected-pokemon', 0, 'The target is attacked with a fiery punch. This may also leave the target with a burn.', 'Has a $effect_chance% chance to burn the target.'),
(8, 'ice-punch', 'ice', 75, 100, 15, 'physical', 'selected-pokemon', 0, 'The target is attacked with an icy punch. This may also leave the target frozen.', 'Has a $effect_chance% chance to freeze the target.'),
(9, 'thunder-punch', 'electric', 75, 100, 15, 'physical', 'selected-pokemon', 0, 'The target is attacked with an electrified punch. This may also leave the target with paralysis.', 'Has a $effect_chance% chance to paralyze the target.'),
(10, 'scratch', 'normal', 40, 100, 35, 'physical', 'selected-pokemon', 0, 'Hard, pointed, sharp claws rake the target to inflict damage.', 'Inflicts regular damage with no additional effect.'),
(11, 'vice-grip', 'normal', 55, 100, 30, 'physical', 'selected-pokemon', 0, 'The target is gripped and squeezed from both sides to inflict damage.', 'Inflicts regular damage with no additional effect.'),
(12, 'guillotine', 'normal', NULL, 30, 5, 'physical', 'selected-pokemon', 0, 'A vicious tearing attack with big pincers. The target faints instantly if this attack hits.', 'Causes a one-hit KO.'),
(13, 'razor-wind', 'normal', 80, 100, 10, 'special', 'all-opponents', 0, 'This move can’t be used. It’s recommended that this move is forgotten. Once forgotten, this move can’t be remembered.', 'Requires a turn to charge before attacking.'),
(14, 'swords-dance', 'normal', NULL, NULL, 20, 'status', 'user', 0, 'A frenetic dance to uplift the fighting spirit. This sharply boosts the user''s Attack stat.', 'Raises the user''s Attack by two stages.'),
(15, 'cut', 'normal', 50, 95, 30, 'physical', 'selected-pokemon', 0, 'The target is cut with a scythe or claw.', 'Inflicts regular damage with no additional effect.'),
(16, 'gust', 'flying', 40, 100, 35, 'special', 'selected-pokemon', 0, 'A gust of wind is whipped up by wings and launched at the target to inflict damage.', 'Inflicts regular damage and can hit Pokémon in the air.'),
(17, 'wing-attack', 'flying', 60, 100, 35, 'physical', 'selected-pokemon', 0, 'The target is struck with large, imposing wings spread wide to inflict damage.', 'Inflicts regular damage with no additional effect.'),
(18, 'whirlwind', 'normal', NULL, NULL, 20, 'status', 'selected-pokemon', -6, 'The target is blown away, and a different Pokémon is dragged out. In the wild, this ends a battle against a single Pokémon.', 'Immediately ends wild battles.  Forces trainers to switch Pokémon.'),
(19, 'fly', 'flying', 90, 95, 15, 'physical', 'selected-pokemon', 0, 'The user flies up into the sky on the first turn, then attacks on the next turn.', 'User flies high into the air, dodging all attacks, and hits next turn.'),
(20, 'bind', 'normal', 15, 85, 20, 'physical', 'selected-pokemon', 0, 'A long body, tentacles, or the like are used to bind and squeeze the target for four to five turns.', 'Prevents the target from fleeing and inflicts damage for 2-5 turns.'),
(21, 'slam', 'normal', 80, 75, 20, 'physical', 'selected-pokemon', 0, 'The target is slammed with a long tail, vines, or the like to inflict damage.', 'Inflicts regular damage with no additional effect.'),
(22, 'vine-whip', 'grass', 45, 100, 25, 'physical', 'selected-pokemon', 0, 'The target is struck with slender, whiplike vines to inflict damage.', 'Inflicts regular damage with no additional effect.'),
(23, 'stomp', 'normal', 65, 100, 20, 'physical', 'selected-pokemon', 0, 'The user attacks by stomping on the target with a big foot. This may also make the target flinch.', 'Has a $effect_chance% chance to make the target flinch.'),
(24, 'double-kick', 'fighting', 30, 100, 30, 'physical', 'selected-pokemon', 0, 'The user attacks by kicking the target twice in a row using two feet.', 'Hits twice in one turn.'),
(25, 'mega-kick', 'normal', 120, 75, 5, 'physical', 'selected-pokemon', 0, 'The target is attacked by a kick launched with muscle-packed power.', 'Inflicts regular damage with no additional effect.'),
(26, 'jump-kick', 'fighting', 100, 95, 10, 'physical', 'selected-pokemon', 0, 'This move can’t be used. It’s recommended that this move is forgotten. Once forgotten, this move can’t be remembered.', 'If the user misses, it takes half the damage it would have inflicted in recoil.'),
(27, 'rolling-kick', 'fighting', 60, 85, 15, 'physical', 'selected-pokemon', 0, 'This move can’t be used. It’s recommended that this move is forgotten. Once forgotten, this move can’t be remembered.', 'Has a $effect_chance% chance to make the target flinch.'),
(28, 'sand-attack', 'ground', NULL, 100, 15, 'status', 'selected-pokemon', 0, 'Sand is hurled in the target''s face, lowering the target''s accuracy.', 'Lowers the target''s accuracy by one stage.'),
(29, 'headbutt', 'normal', 70, 100, 15, 'physical', 'selected-pokemon', 0, 'The user sticks out its head and attacks by charging straight into the target. This may also make the target flinch.', 'Has a $effect_chance% chance to make the target flinch.'),
(30, 'horn-attack', 'normal', 65, 100, 25, 'physical', 'selected-pokemon', 0, 'The target is jabbed with a sharply pointed horn to inflict damage.', 'Inflicts regular damage with no additional effect.'),
(31, 'fury-attack', 'normal', 15, 85, 20, 'physical', 'selected-pokemon', 0, 'The user attacks by jabbing the target with a horn, a beak, or the like. This move hits two to five times in a row.', 'Hits 2-5 times in one turn.'),
(32, 'horn-drill', 'normal', NULL, 30, 5, 'physical', 'selected-pokemon', 0, 'The user stabs the target with a horn that rotates like a drill. The target faints instantly if this attack hits.', 'Causes a one-hit KO.'),
(33, 'tackle', 'normal', 40, 100, 35, 'physical', 'selected-pokemon', 0, 'A physical attack in which the user charges and slams into the target with its whole body.', 'Inflicts regular damage with no additional effect.'),
(34, 'body-slam', 'normal', 85, 100, 15, 'physical', 'selected-pokemon', 0, 'The user attacks by dropping onto the target with its full body weight. This may also leave the target with paralysis.', 'Has a $effect_chance% chance to paralyze the target.'),
(35, 'wrap', 'normal', 15, 90, 20, 'physical', 'selected-pokemon', 0, 'A long body, vines, or the like are used to wrap and squeeze the target for four to five turns.', 'Prevents the target from fleeing and inflicts damage for 2-5 turns.'),
(36, 'take-down', 'normal', 90, 85, 20, 'physical', 'selected-pokemon', 0, 'A reckless full-body charge attack for slamming into the target. This also damages the user a little.', 'User receives 1/4 the damage it inflicts in recoil.'),
(37, 'thrash', 'normal', 120, 100, 10, 'physical', 'random-opponent', 0, 'The user rampages and attacks for two to three turns. The user then becomes confused.', 'Hits every turn for 2-3 turns, then confuses the user.'),
(38, 'double-edge', 'normal', 120, 100, 15, 'physical', 'selected-pokemon', 0, 'A reckless life-risking tackle in which the user rushes the target. This also damages the user quite a lot.', 'User receives 1/3 the damage inflicted in recoil.'),
(39, 'tail-whip', 'normal', NULL, 100, 30, 'status', 'all-opponents', 0, 'The user wags its tail cutely, making opposing Pokémon less wary. This lowers their Defense stats.', 'Lowers the target''s Defense by one stage.'),
(40, 'poison-sting', 'poison', 15, 100, 35, 'physical', 'selected-pokemon', 0, 'The user stabs the target with a poisonous stinger to inflict damage. This may also poison the target.', 'Has a $effect_chance% chance to poison the target.'),
(41, 'twineedle', 'bug', 25, 100, 20, 'physical', 'selected-pokemon', 0, 'This move can’t be used. It’s recommended that this move is forgotten. Once forgotten, this move can’t be remembered.', 'Hits twice in the same turn.  Has a $effect_chance% chance to poison the target.'),
(42, 'pin-missile', 'bug', 25, 95, 20, 'physical', 'selected-pokemon', 0, 'The user attacks by shooting sharp spikes at the target. This move hits two to five times in a row.', 'Hits 2-5 times in one turn.'),
