(69, 'seismic-toss', 'fighting', NULL, 100, 20, 'physical', 'selected-pokemon', 0, 'The target is thrown using the power of gravity. It inflicts damage equal to the user''s level.', 'Inflicts damage equal to the user''s level.'),
