(570, 'parabolic-charge', 'electric', 65, 100, 20, 'special', 'all-other-pokemon', 0, 'The user attacks everything around it. The user''s HP is restored by half the damage taken by those hit.', 'Heals the user for half the total damage dealt to all targets.'),
(571, 'forests-curse', 'grass', NULL, 100, 20, 'status', 'selected-pokemon', 0, 'The user puts a forest curse on the target. This adds Grass type to the target''s type.', 'Adds grass to the target''s types.'),
(572, 'petal-blizzard', 'grass', 90, 100, 15, 'physical', 'all-other-pokemon', 0, 'The user stirs up a violent petal blizzard and damages everything around it.', 'Inflicts regular damage.'),
(573, 'freeze-dry', 'ice', 70, 100, 20, 'special', 'selected-pokemon', 0, 'The user rapidly cools the target. This may also leave the target frozen. This move is super effective on Water types.', 'Super-effective against water.'),
(574, 'disarming-voice', 'fairy', 40, NULL, 15, 'special', 'all-opponents', 0, 'Letting out a charming cry, the user does emotional damage to opposing Pokémon. This attack never misses.', 'Never misses.'),
(575, 'parting-shot', 'dark', NULL, 100, 20, 'status', 'selected-pokemon', 0, 'With a parting threat, the user lowers the target''s Attack and Sp. Atk stats. Then it switches places with a party Pokémon in waiting.', 'Lowers all targets'' Attack and Special Attack by one stage.  Makes the user switch out.'),
(576, 'topsy-turvy', 'dark', NULL, NULL, 20, 'status', 'selected-pokemon', 0, 'All stat changes affecting the target turn topsy-turvy and become the opposite of what they were.', 'Inverts the target''s stat modifiers.'),
(577, 'draining-kiss', 'fairy', 50, 100, 10, 'special', 'selected-pokemon', 0, 'The user steals the target''s HP with a kiss. The user''s HP is restored by over half the damage taken by the target.', 'Drains 75% of the damage inflicted to heal the user.'),
(578, 'crafty-shield', 'fairy', NULL, NULL, 10, 'status', 'users-field', 3, 'The user protects itself and its allies from status moves with a mysterious power. This does not stop moves that do damage.', 'Protects all friendly Pokémon from non-damaging moves.'),
(579, 'flower-shield', 'fairy', NULL, NULL, 10, 'status', 'all-pokemon', 0, 'The user raises the Defense stats of all Grass-type Pokémon in battle with a mysterious power.', 'Raises the Defense of all grass Pokémon in battle.'),
(580, 'grassy-terrain', 'grass', NULL, NULL, 10, 'status', 'entire-field', 0, 'The user turns the ground into Grassy Terrain for five turns. This restores the HP of Pokémon on the ground a little every turn and powers up Grass-type moves.', 'For five turns, heals all Pokémon on the ground for 1/16 max HP each turn and strengthens their grass moves to 1.5× their power.'),
(581, 'misty-terrain', 'fairy', NULL, NULL, 10, 'status', 'entire-field', 0, 'This protects Pokémon on the ground from status conditions and halves damage from Dragon-type moves for five turns.', 'For five turns, protects all Pokémon on the ground from major status ailments and confusion, and halves the power of incoming dragon moves.'),
(582, 'electrify', 'electric', NULL, NULL, 20, 'status', 'selected-pokemon', 0, 'If the target is electrified before it uses a move during that turn, the target’s move becomes Electric type.', 'Changes the target''s move''s type to electric if it hasn''t moved yet this turn.'),
(583, 'play-rough', 'fairy', 90, 90, 10, 'physical', 'selected-pokemon', 0, 'The user attacks by playing rough with the target. This may also lower the target''s Attack stat.', 'Has a $effect_chance% chance to lower the target''s Attack by one stage.'),
(584, 'fairy-wind', 'fairy', 40, 100, 30, 'special', 'selected-pokemon', 0, 'The user attacks by stirring up a fairy wind to strike the target.', 'Inflicts regular damage with no additional effect.'),
(585, 'moonblast', 'fairy', 95, 100, 15, 'special', 'selected-pokemon', 0, 'Borrowing the power of the moon, the user attacks the target. This may also lower the target''s Sp. Atk stat.', 'Has a $effect_chance% chance to lower the target''s Special Attack by one stage.'),
(586, 'boomburst', 'normal', 140, 100, 10, 'special', 'all-other-pokemon', 0, 'The user attacks everything around it with the destructive power of a terrible explosive sound.', 'Inflicts regular damage.'),
(587, 'fairy-lock', 'fairy', NULL, NULL, 10, 'status', 'entire-field', 0, 'By locking down the battlefield, the user keeps all Pokémon from fleeing during the next turn.', 'Prevents all Pokémon from fleeing or switching out during the next turn.'),
(588, 'kings-shield', 'steel', NULL, NULL, 10, 'status', 'user', 4, 'The user takes a defensive stance while it protects itself from damage. It also lowers the Attack stat of any attacker that makes direct contact.', 'Blocks damaging attacks and lowers attacking Pokémon''s Attack by two stages on contact.  Switches Aegislash to Shield Forme.'),
(589, 'play-nice', 'normal', NULL, NULL, 20, 'status', 'selected-pokemon', 0, 'The user and the target become friends, and the target loses its will to fight. This lowers the target''s Attack stat.', 'Lowers the target''s Attack by one stage.'),
(590, 'confide', 'normal', NULL, NULL, 20, 'status', 'selected-pokemon', 0, 'The user tells the target a secret, and the target loses its ability to concentrate. This lowers the target''s Sp. Atk stat.', 'Lowers the target''s Special Attack by one stage.'),
(591, 'diamond-storm', 'rock', 100, 95, 5, 'physical', 'all-opponents', 0, 'The user whips up a storm of diamonds to damage opposing Pokémon. This may also sharply boost the user''s Defense stat.', 'Has a $effect_chance% chance to raise the user''s Defense by two stages for each target hit.'),
(592, 'steam-eruption', 'water', 110, 95, 5, 'special', 'selected-pokemon', 0, 'The user immerses the target in superheated steam. This may also leave the target with a burn.', 'Has a $effect_chance% chance to burn the target.'),
(593, 'hyperspace-hole', 'psychic', 80, NULL, 5, 'special', 'selected-pokemon', 0, 'Using a hyperspace hole, the user appears right next to the target and strikes. This attack can hit a target using a move such as Protect or Detect.', 'Ignores and destroys protection effects.'),
(594, 'water-shuriken', 'water', 15, 100, 20, 'special', 'selected-pokemon', 1, 'The user hits the target with throwing stars two to five times in a row. This move always goes first.', 'Hits 2–5 times.'),
(595, 'mystical-fire', 'fire', 75, 100, 10, 'special', 'selected-pokemon', 0, 'The user attacks by breathing a special, hot fire. This also lowers the target''s Sp. Atk stat.', 'Has a $effect_chance% chance to lower the target''s Special Attack by one stage.'),
(596, 'spiky-shield', 'grass', NULL, NULL, 10, 'status', 'user', 4, 'In addition to protecting the user from attacks, this move also damages any attacker that makes direct contact.', 'Blocks damaging attacks and damages attacking Pokémon for 1/8 their max HP.'),
(597, 'aromatic-mist', 'fairy', NULL, NULL, 20, 'status', 'ally', 0, 'The user boosts the Sp. Def stat of an ally Pokémon by using a mysterious aroma.', 'Raises a selected ally''s Special Defense by one stage.'),
(598, 'eerie-impulse', 'electric', NULL, 100, 15, 'status', 'selected-pokemon', 0, 'The user''s body generates an eerie impulse. Exposing the target to it harshly lowers the target''s Sp. Atk stat.', 'Lowers the target''s Special Attack by two stages.'),
(599, 'venom-drench', 'poison', NULL, 100, 20, 'status', 'all-opponents', 0, 'Opposing Pokémon are drenched in an odd poisonous liquid. This lowers the Attack, Sp. Atk, and Speed stats of a poisoned target.', 'Lowers the target''s Attack, Special Attack, and Speed by one stage if it is poisoned.'),
(600, 'powder', 'bug', NULL, 100, 20, 'status', 'selected-pokemon', 1, 'The user covers the target in a combustible powder. If the target uses a Fire-type move, the powder explodes and damages the target.', 'Explodes if the target uses a fire move this turn, damaging it for 1/4 its max HP and preventing the move.'),
(601, 'geomancy', 'fairy', NULL, NULL, 10, 'status', 'user', 0, 'The user absorbs energy and sharply raises its Sp. Atk, Sp. Def, and Speed stats on the next turn.', 'Takes one turn to charge, then raises the user''s Special Attack, Special Defense, and Speed by two stages.'),
(602, 'magnetic-flux', 'electric', NULL, NULL, 20, 'status', 'user-and-allies', 0, 'The user manipulates magnetic fields, which boosts the Defense and Sp. Def stats of ally Pokémon with the Plus Ability or the Minus Ability.', 'Raises the Defense and Special Defense of all friendly Pokémon with plus or minus by one stage.'),
(603, 'happy-hour', 'normal', NULL, NULL, 30, 'status', 'users-field', 0, 'Using Happy Hour doubles the amount of prize money received after battle.', 'Doubles prize money.'),
(604, 'electric-terrain', 'electric', NULL, NULL, 10, 'status', 'entire-field', 0, 'The user turns the ground into Electric Terrain for five turns, powering up Electric-type moves. Pokémon on the ground can no longer fall asleep.', 'For five turns, prevents all Pokémon on the ground from sleeping and strengthens their electric moves to 1.5× their power.'),
(605, 'dazzling-gleam', 'fairy', 80, 100, 10, 'special', 'all-opponents', 0, 'The user damages opposing Pokémon by emitting a powerful flash.', 'Inflicts regular damage with no additional effect.'),
(606, 'celebrate', 'normal', NULL, NULL, 40, 'status', 'user', 0, 'The Pokémon congratulates you on your special day!', 'Does nothing.'),
(607, 'hold-hands', 'normal', NULL, NULL, 40, 'status', 'ally', 0, 'The user and an ally hold hands. This makes them very happy.', 'Does nothing.'),
(608, 'baby-doll-eyes', 'fairy', NULL, 100, 30, 'status', 'selected-pokemon', 1, 'The user stares at the target with its baby-doll eyes, which lowers the target''s Attack stat. This move always goes first.', 'Lowers the target''s Attack by one stage.'),
(609, 'nuzzle', 'electric', 20, 100, 20, 'physical', 'selected-pokemon', 0, 'The user attacks by nuzzling its electrified cheeks against the target. This also leaves the target with paralysis.', 'Has a $effect_chance% chance to paralyze the target.'),
(610, 'hold-back', 'normal', 40, 100, 40, 'physical', 'selected-pokemon', 0, 'The user holds back when it attacks, and the target is left with at least 1 HP.', 'Cannot lower the target''s HP below 1.'),
(611, 'infestation', 'bug', 20, 100, 20, 'special', 'selected-pokemon', 0, 'The target is infested and attacked for four to five turns. The target can''t flee during this time.', 'Prevents the target from fleeing and inflicts damage for 2-5 turns.'),
(612, 'power-up-punch', 'fighting', 40, 100, 20, 'physical', 'selected-pokemon', 0, 'Striking opponents over and over makes the user’s fists harder. Hitting a target raises the Attack stat.', 'Raises the user''s Attack by one stage after inflicting damage.'),
(613, 'oblivion-wing', 'flying', 80, 100, 10, 'special', 'selected-pokemon', 0, 'The user absorbs its target’s HP. The user’s HP is restored by over half of the damage taken by the target.', 'Drains 75% of the damage inflicted to heal the user.'),
(614, 'thousand-arrows', 'ground', 90, 100, 10, 'physical', 'all-opponents', 0, 'This move also hits opposing Pokémon that are in the air. Those Pokémon are knocked down to the ground.', 'Grounds the target, and hits even Flying-type or levitating Pokémon.'),
