(913, 'dragon-cheer', 'dragon', 0, 0, 15, 'status', 'all-allies', 0, 'The user raises its allies’ morale with a draconic cry so that their future attacks have a heightened chance of landing critical hits. This rouses Dragon types more.', ''),
(914, 'alluring-voice', 'fairy', 80, 100, 10, 'special', 'selected-pokemon', 0, 'The user attacks the target using its angelic voice. This also confuses the target if its stats have been boosted during the turn.', ''),
(915, 'temper-flare', 'fire', 75, 100, 10, 'physical', 'selected-pokemon', 0, 'Spurred by desperation, the user attacks the target. This move''s power is doubled if the user''s previous move failed.', ''),
(916, 'supercell-slam', 'electric', 100, 95, 15, 'physical', 'selected-pokemon', 0, 'The user electrifies its body and drops onto the target to inflict damage. If this move misses, the user takes damage instead.', ''),
(917, 'psychic-noise', 'psychic', 75, 100, 10, 'special', 'selected-pokemon', 0, 'The user attacks the target with unpleasant sound waves. For two turns, the target is prevented from recovering HP through moves, Abilities, or held items.', ''),
(918, 'upper-hand', 'fighting', 65, 100, 15, 'physical', 'selected-pokemon', 3, 'The user reacts to the target''s movement and strikes with the heel of its palm, making the target flinch. This move fails if the target is not readying a priority move.', ''),
(919, 'malignant-chain', 'poison', 100, 100, 5, 'special', 'selected-pokemon', 0, 'The user pours toxins into the target by wrapping them in a toxic, corrosive chain. This may also leave the target badly poisoned.', ''),
(10001, 'shadow-rush', 'shadow', 55, 100, NULL, 'physical', 'selected-pokemon', 0, '', 'Has an increased chance for a critical hit in Hyper Mode.'),
(10002, 'shadow-blast', 'shadow', 80, 100, NULL, 'physical', 'selected-pokemon', 0, '', 'Has an increased chance for a critical hit.'),
(10003, 'shadow-blitz', 'shadow', 40, 100, NULL, 'physical', 'selected-pokemon', 0, '', 'Inflicts regular damage with no additional effect.'),
(10004, 'shadow-bolt', 'shadow', 75, 100, NULL, 'special', 'selected-pokemon', 0, '', 'Has a $effect_chance% chance to paralyze the target.'),
(10005, 'shadow-break', 'shadow', 75, 100, NULL, 'physical', 'selected-pokemon', 0, '', 'Inflicts regular damage with no additional effect.'),
(10006, 'shadow-chill', 'shadow', 75, 100, NULL, 'special', 'selected-pokemon', 0, '', 'Has a $effect_chance% chance to freeze the target.'),
(10007, 'shadow-end', 'shadow', 120, 60, NULL, 'physical', 'selected-pokemon', 0, '', 'User receives 1/2 its HP in recoil.'),
(10008, 'shadow-fire', 'shadow', 75, 100, NULL, 'special', 'selected-pokemon', 0, '', 'Has a $effect_chance% chance to burn the target.'),
(10009, 'shadow-rave', 'shadow', 70, 100, NULL, 'special', 'opponents-field', 0, '', 'Inflicts regular damage with no additional effect.'),
(10010, 'shadow-storm', 'shadow', 95, 100, NULL, 'special', 'opponents-field', 0, '', 'Inflicts regular damage with no additional effect.'),
(10011, 'shadow-wave', 'shadow', 50, 100, NULL, 'special', 'opponents-field', 0, '', 'Inflicts regular damage with no additional effect.'),
(10012, 'shadow-down', 'shadow', NULL, 100, NULL, 'status', 'opponents-field', 0, '', 'Lowers the target''s Defense by two stages.'),
(10013, 'shadow-half', 'shadow', NULL, 100, NULL, 'special', 'entire-field', 0, '', 'Halves HP of all Pokémon on the field.  Must recharge'),
(10014, 'shadow-hold', 'shadow', NULL, NULL, NULL, 'status', 'opponents-field', 0, '', 'Prevents the target from leaving battle.'),
(10015, 'shadow-mist', 'shadow', NULL, 100, NULL, 'status', 'opponents-field', 0, '', 'Lowers the target''s evasion by two stages.'),
(10016, 'shadow-panic', 'shadow', NULL, 90, NULL, 'status', 'opponents-field', 0, '', 'Confuses the target.'),
